import React from 'react';

import "slick-carousel/slick/slick.css"; 
import "slick-carousel/slick/slick-theme.css";

import './css/bootstrap.min.css'; 
import './css/style.css';
import './css/tourvisor.css';

import SearchPage from './pages/SearchPage';
import TourPage from './pages/TourPage';

import Header from './components/Header';
import NavContainer from './components/NavContainer';
import Start from './components/Start';
import SearchBarIndex from './components/SearchBarIndex';
import HotTours from './components/HotTours';
import RecomendedHotels from './components/RecomendedHotels';
import Partners from './components/Partners';
import AdditionServices from './components/AdditionServices';
import AboutCompany from './components/AboutCompany';
import Footer from './components/Footer';

function App() {
  return (
    <>
<div className="App">
  {"{"}
  <Header />
  <NavContainer />
  <Start />
  <SearchBarIndex />
  <HotTours />
  <RecomendedHotels />
  <Partners />
  <AdditionServices />
  <AboutCompany />
  <Footer />
  <noscript>
    &lt;div&gt;&lt;img src="/images/657430.gif" style="position: absolute; left:
    -9999px" alt="" /&gt;&lt;/div &gt;
  </noscript>
  {/* /Yandex.Metrika counter */}
  <noscript>
    &lt;div&gt; &lt;img src="/images/counter.gif" style="border: 0; position:
    absolute; left: -9999px" alt="Top.Mail.Ru" /&gt;&lt;/div &gt;
  </noscript>
  <scrip>
    $(document).ready(function () {"{"}
    // Инициализация слайдера со всеми настройками автоплея
    $(".banner-box").slick({"{"}
    dots: true, // Показывать кружочки infinite: true, // Бесконечная прокрутка
    (с 12-го на 1-й) slidesToShow: 1, // По одному слайду за раз slidesToScroll:
    1, // Листать по одному слайду autoplay: true, // ВКЛЮЧИТЬ автопереключение
    autoplaySpeed: 3000, // Смена каждые 3 секунды speed: 800, // Скорость самой
    анимации перехода (плавность) arrows: false, // Скрыть стрелки (если нужны
    только точки) pauseOnHover: false, // Не останавливать, если наведен курсор
    pauseOnFocus: false, // Не останавливать при клике
    {"}"});
    {"}"});
    {"}"}
  </scrip>
</div>


</>
  );
}

export default App;
